//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "Table widths, grid, indent, and layout algorithm".
//!
//! Each `#[test]` encodes a behaviour the OOXML / Word specification requires of
//! a faithful DOCX engine. A FAILING assertion here is NOT a flaky test to be
//! silenced: it encodes a real Word-compliance GAP in stemma (the engine
//! diverges from how Microsoft Word consumes / serializes the markup). The fix
//! is in the engine (model + serializer), never in weakening the assertion.
//!
//! Methodology note (consumption vs. save): stemma round-trips UNTOUCHED content
//! byte-verbatim. So `reserialize()` of an unedited doc reflects stemma's
//! verbatim-preservation contract, NOT Word's render normalization. The xml*
//! checks below are therefore only used for markup stemma's serializer ACTIVELY
//! generates/restructures — tables are reconstructed from the typed model
//! (`serialize_table_node`), so a row/cell property the typed model does not
//! carry is genuinely DROPPED on save (true content loss), and CT_Tbl child
//! ORDERING is genuinely the serializer's job. opensClean tests assert the
//! validator finds no errors for a schema-valid width form Word tolerates;
//! a parse failure on such a form is the divergence we are hunting.

use std::io::{Cursor, Read, Write};

use stemma::ExportOptions;
use stemma::api::{Document, validate};
use zip::ZipWriter;
use zip::write::FileOptions;

// ─── Prelude / helpers ───────────────────────────────────────────────────────

/// Build a valid minimal `.docx`. `body_xml` is wrapped in
/// `<w:document …><w:body>…</w:body></w:document>`. `extra_parts` are
/// `(part_name, xml)` pairs (e.g. `("word/styles.xml", …)`); each gets a
/// content-type override keyed off its part name.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    let mut overrides = String::new();
    for (part_name, _) in extra_parts {
        let (part_path, content_type) = match *part_name {
            "word/styles.xml" => (
                "/word/styles.xml",
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml",
            ),
            "word/numbering.xml" => (
                "/word/numbering.xml",
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml",
            ),
            other => {
                panic!("make_docx: no content-type override registered for extra part {other}")
            }
        };
        overrides.push_str(&format!(
            r#"<Override PartName="{part_path}" ContentType="{content_type}"/>"#
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#;

    let mut buf = Vec::new();
    {
        let mut zip = ZipWriter::new(Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part_name, xml) in extra_parts {
            zip.start_file(*part_name, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let mut zip = zip::ZipArchive::new(Cursor::new(docx)).expect("open docx zip");
    let mut file = zip
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut s = String::new();
    file.read_to_string(&mut s).expect("read document.xml");
    s
}

/// Parse → serialize(default) → return the re-emitted `word/document.xml`.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

/// `validate` reports no errors.
fn opens_clean(bytes: &[u8]) -> bool {
    validate(bytes).ok
}

/// The validation report rendered for an assert message.
fn report_str(bytes: &[u8]) -> String {
    let r = validate(bytes);
    format!("ok={} issues={:?}", r.ok, r.issues)
}

/// xmlRegex of the shape `A ... B ... C` (each followed by arbitrary markup):
/// true iff each part occurs and at strictly increasing byte offsets. The regex
/// crate is not a dev-dependency, but for "X precedes Y precedes Z" the
/// first-index ordering is faithful.
fn ordered(xml: &str, parts: &[&str]) -> bool {
    let mut last: Option<usize> = None;
    for p in parts {
        match xml.find(p) {
            Some(i) => {
                if let Some(l) = last
                    && i <= l
                {
                    return false;
                }
                last = Some(i);
            }
            None => return false,
        }
    }
    true
}

