#[test]
fn gridcol_universal_measure_opens_clean() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="1in"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="1440" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>Inch</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert!(
        opens_clean(&b),
        "ISO 29500-1 §17.4.16 / §22.9.2.14 / §22.9.2.12: gridCol/@w='1in' is a valid ST_TwipsMeasure (union admits a positive universal measure); Word opens it without repair, so validate must report no errors. validate: {}",
        report_str(&b)
    );
}

