#[test]
fn ct_tbl_emits_tblpr_before_tblgrid_before_tr() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="4000" w:type="dxa"/></w:tblPr><w:tblGrid><w:gridCol w:w="2000"/><w:gridCol w:w="2000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="2000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>A</w:t></w:r></w:p></w:tc><w:tc><w:tcPr><w:tcW w:w="2000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>B</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    // xmlRegex `<w:tblPr[\s\S]*<w:tblGrid[\s\S]*<w:tr` => ordering check.
    assert!(
        ordered(&xml, &["<w:tblPr", "<w:tblGrid", "<w:tr"]),
        "ISO 29500-1 §17.4.48 / §17.4.60 / Annex A CT_Tbl: CT_Tbl is the ordered sequence tblPr, tblGrid, EG_ContentRowContent; the serializer must emit tblPr before tblGrid before the first row. Reserialized XML: {xml}"
    );
    assert!(
        opens_clean(&b),
        "ISO 29500-1 Annex A CT_Tbl: a table whose children follow the CT_Tbl sequence is schema-valid and Word opens it without repair. validate: {}",
        report_str(&b)
    );
}

