#[test]
fn wbefore_survives_reserialization() {
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="2000"/><w:gridCol w:w="2000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="2000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>A1</w:t></w:r></w:p></w:tc><w:tc><w:tcPr><w:tcW w:w="2000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>B1</w:t></w:r></w:p></w:tc></w:tr><w:tr><w:trPr><w:gridBefore w:val="1"/><w:wBefore w:w="2000" w:type="dxa"/></w:trPr><w:tc><w:tcPr><w:tcW w:w="2000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>B2</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains("<w:wBefore"),
        "ISO 29500-1 §17.4.86 / §17.18.87: wBefore sizes the skipped leading grid columns (consumed by the fixed-width layout algorithm) and Word preserves it; a faithful round-trip must re-emit it rather than silently drop it. Reserialized XML: {xml}"
    );
    assert!(
        xml.contains("<w:gridBefore"),
        "ISO 29500-1 §17.4.14: gridBefore is the paired skipped-column count; it must remain so the re-emitted wBefore still has the columns it sizes. Reserialized XML: {xml}"
    );
}

