#[test]
fn tblw_and_tcw_percent_form_widths_survive_redline() {
    use stemma::{DocxRuntime, ExportMode, SimpleRuntime, TransactionMeta};
    // ISO 29500-1 §17.18.107: percent-form widths ("100%", "40.0%") are valid
    // ST_MeasurementOrPercent values. Redline path: edit a DIFFERENT
    // paragraph, export tracked changes, reparse — the widths (and their
    // spelling: tables are rebuilt on save) must survive.
    let body = |text: &str| {
        format!(
            r#"<w:tbl><w:tblPr><w:tblW w:w="100%" w:type="pct"/></w:tblPr><w:tblGrid><w:gridCol w:w="2000"/><w:gridCol w:w="3000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="40.0%" w:type="pct"/></w:tcPr><w:p><w:r><w:t>A</w:t></w:r></w:p></w:tc><w:tc><w:p><w:r><w:t>B</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:p><w:r><w:t>{text}</w:t></w:r></w:p><w:sectPr/>"#
        )
    };
    let base_bytes = make_docx(&body("Trailing paragraph."), &[]);
    let edited_bytes = make_docx(&body("Trailing paragraph, edited."), &[]);

    let runtime = SimpleRuntime::new();
    let base = runtime.import_docx(&base_bytes).expect("import base");
    let edited = runtime.import_docx(&edited_bytes).expect("import edited");
    let meta = TransactionMeta {
        author: "spec_table_widths".to_string(),
        reason: Some("percent-width redline survival".to_string()),
        timestamp_utc: Some("2025-01-15T10:30:00Z".to_string()),
    };
    let apply = runtime
        .diff_and_redline(&base.doc_handle, &edited.doc_handle, meta)
        .expect("diff_and_redline");
    assert!(apply.applied, "redline should be applied");
    let redline = runtime
        .export_docx(&base.doc_handle, ExportMode::Redline)
        .expect("export redline");

    let xml = document_xml_of(&redline);
    assert!(
        xml.contains("100%") && xml.contains("40.0%"),
        "percent-form tblW/tcW must survive the redline export in their source spelling. XML: {xml}"
    );
    assert!(
        xml.contains("edited"),
        "the paragraph edit must appear in the redline output. XML: {xml}"
    );
    // The redline output itself must reparse (percent forms round again).
    let runtime2 = SimpleRuntime::new();
    runtime2
        .import_docx(&redline)
        .expect("redline output with percent-form widths must reparse");
}

#[test]
fn tcw_illegal_width_value_still_fails_fast() {
    use stemma::api::Document;
    // Accepting the full ST_MeasurementOrPercent union must NOT open the door
    // to garbage: "abc" matches none of the three legal forms (decimal,
    // percent literal, universal measure) and stays a hard InvalidDocx error.
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="abc" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>cell</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let err = match Document::parse(&b) {
        Ok(_) => panic!("a non-numeric non-measure width must be rejected"),
        Err(e) => e,
    };
    let msg = format!("{err:?}");
    assert!(
        msg.contains("abc") && msg.contains("tcW"),
        "error should name the bad value and the carrier element, got: {msg}"
    );
}

#[test]
fn gridcol_universal_measure_parses_to_twips() {
    use stemma::{DocxRuntime, SimpleRuntime};
    // §22.9.2.14 ST_TwipsMeasure: gridCol/@w admits a positive universal
    // measure. "1in" = 1440 twips; the parse must accept it (it used to fail
    // the whole Document::parse) and normalize it in the typed model, so a
    // rebuilt grid emits a legal twips value.
    let body = r#"<w:tbl><w:tblPr><w:tblW w:w="0" w:type="auto"/></w:tblPr><w:tblGrid><w:gridCol w:w="1in"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="1440" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>Inch</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let runtime = SimpleRuntime::new();
    let import = runtime
        .import_docx(&b)
        .expect("gridCol universal measure must parse");
    let view = runtime.view(&import.doc_handle).expect("view");
    let grid_cols = view
        .canonical
        .blocks
        .iter()
        .find_map(|tb| match &tb.block {
            stemma::BlockNode::Table(t) => Some(t.formatting.grid_cols.clone()),
            _ => None,
        })
        .expect("document contains the table");
    assert_eq!(
        grid_cols,
        vec![1440],
        "gridCol '1in' must normalize to 1440 twips in the typed model"
    );
}
